worked_example.final_code:
import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;

record StockQuote(String symbol, double price, double change) {}

public class StockFetcher {
    static Callable<StockQuote> fetchQuote(String symbol) {
        return () -> {
            Thread.sleep(50 + (int)(Math.random() * 150));
            if (symbol.equals("BADSTOCK")) throw new RuntimeException("Not found: " + symbol);
            double price  = 500 + Math.random() * 3500;
            double change = -4 + Math.random() * 8;
            return new StockQuote(symbol, price, change);
        };
    }

    public static void main(String[] args) throws InterruptedException {
        List<String> symbols = Arrays.asList(
            "RELIANCE", "TCS", "INFY", "HDFC", "WIPRO",
            "ZOMATO", "NYKAA", "BAJFINANCE", "DMART", "PAYTM");

        ExecutorService pool = Executors.newFixedThreadPool(4);
        long start = System.currentTimeMillis();

        List<Future<StockQuote>> futures = pool.invokeAll(
            symbols.stream().map(StockFetcher::fetchQuote).collect(Collectors.toList()));

        List<StockQuote> quotes = new ArrayList<>();
        for (int i = 0; i < futures.size(); i++) {
            try {
                quotes.add(futures.get(i).get());
            } catch (ExecutionException e) {
                System.err.println("Failed: " + symbols.get(i));
            }
        }

        System.out.printf("Fetched %d quotes in %dms%n",
            quotes.size(), System.currentTimeMillis() - start);
        System.out.println("\nSymbol       Price    Change");
        System.out.println("-".repeat(35));

        quotes.stream()
            .sorted((a, b) -> Double.compare(b.change(), a.change()))
            .forEach(q -> System.out.printf("%-12s ₹%6.0f  %+5.1f%%%n",
                q.symbol(), q.price(), q.change()));

        pool.shutdown();
        pool.awaitTermination(10, TimeUnit.SECONDS);
    }
}
